			$wpdb->prepare(
				"SELECT COUNT(ID) FROM {$subquery}
					WHERE post_status IN ("
						. implode( ', ', array_fill( 0, count( $states ), '%s' ) )
					. ')',
				$states,
			),
		)

$wpdb->get_results(
					$wpdb->prepare(
						"SELECT DISTINCT post_type FROM {$subquery}
							WHERE post_status IN ("
